# search for hadiths containing tokens 'المؤمن' and 'الدنيا' and 'الآخرة' in normalized text
candidates_all = []
for idx, h in enumerate(hadiths):
    cand = h.get('hadithTxt') or h.get('Matn') or ""
    if not cand:
        continue
    norm_cand = normalize_arabic(cand)
    if 'المؤمن' in norm_cand and 'الدنيا' in norm_cand and ('الاخرة' in norm_cand or 'الءخرة' in norm_cand or 'اخرة' in norm_cand):
        candidates_all.append((idx, cand, norm_cand))
len(candidates_all)
